  VALUES ('vol00009-efta00720472-pdf', 'vol00009-efta00720472-pdf', 'Gregory Brown <gbrown1970@gmail.com>', 'West freezes billions of dollars from Libya’s sovereign wealth funds', '["Victor Gao <gaovictor@>","Joel Motley <motley@publiccapitaladvisors.com>"]', '2011-08-02T15:59:55.000Z', 'Egypt, Libya, Tunisia', 9, 0, 0, ' gregory brown <gbrown1970@gmail.com> ["victor gao <gaovictor@>", "joel motley <motley@publiccapitaladvisors.com>"] [] ["jeevacation@gmail.com"] ', 'FYI......
