  VALUES ('vol00009-efta00974820-pdf', 'vol00009-efta00974820-pdf', 'Jeffrey Epstein <jeevacation@gmail.com>', 'Fwd: Fw: Bill Gates should not visit Nigeria', '["Boris Nikolic"]', '2013-11-05T18:34:42.000Z', 'Nigeria', 9, 1, 0, ' jeffrey epstein <jeevacation@gmail.com> ["boris nikolic"] [] [] ', 'Forwarded message
From: Terje Rod-Larsen
